sys_script_include.script:
var DepartmentHelper = Class.create();
DepartmentHelper.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getDepartment: function() {

        var branch = this.getParameter('sysparm_branch');

        if (branch == 'cse')
            return 'Computer Science Engineering';

        if (branch == 'ece')
            return 'Electronics & Communication';

        if (branch == 'aids')
            return 'Artificial Intelligence & Data Science';

        if (branch == 'aiml')
            return 'Artificial Intelligence & Machine Learning';

        if (branch == 'mba')
            return 'Management Studies';

        if (branch == 'bba')
            return 'Business Administration';

        if (branch == 'me')
            return 'Mechanical Engineering';

        return '';
    },

    type: 'DepartmentHelper'
});
